12	@Injectable()
13	export class LoggingInterceptor implements NestInterceptor {
14	  constructor(private readonly observability: ObservabilityService) {}
15	
16	  intercept(context: ExecutionContext, next: CallHandler): Observable<unknown> {
17	    const req = context.switchToHttp().getRequest<{
18	      method: string;
19	      url: string;
20	      user?: { id?: string };
21	      requestId?: string;
22	      body?: unknown;
23	    }>();
