39	      tap(() => {
40	        if (isNoise) return;
41	        const res = context.switchToHttp().getResponse<{ statusCode: number }>();
42	        const statusCode = res.statusCode;
43	        const durationMs = Date.now() - start;
44	        void this.observability.writeLog({
45	          requestId,
46	          userId,
47	          level: statusCode >= 500 ? 'ERROR' : statusCode >= 400 ? 'WARN' : 'INFO',
48	          service: 'HTTP',
49	          message: `${method} ${path} ${statusCode}`,
50	          method,
51	          path,
52	          statusCode,
53	          durationMs,
54	        });
55	      }),
56	      catchError((err: unknown) => {
57	        if (!isNoise) {
58	          const statusCode =
59	            typeof err === 'object' && err !== null && 'status' in err
60	              ? (err as { status: number }).status
61	              : 500;
62	          const message =
63	            typeof err === 'object' && err !== null && 'message' in err
64	              ? String((err as { message: unknown }).message)
65	              : 'Internal error';
